import{_ as n,W as o,X as i,Z as r,$ as e,a1 as t,a0 as l,C as h}from"./framework-91490e6a.js";const p={},s=l('<h1 id="不同角度对安全的定义" tabindex="-1"><a class="header-anchor" href="#不同角度对安全的定义" aria-hidden="true">#</a> 不同角度对安全的定义</h1><p><strong>密码系统安全性应满足的条件</strong></p><ol><li>系统在理论上是不会被破译的，也不能在实践中被破译。</li><li>系统的机密性不依赖于加密/解密算法和系统的加密，而只取决于密钥的机密性。</li><li>易于添加/解密操作、在软件/硬件中快速且易于实现。</li><li>加密/解密算法对密钥空间的全部元素均可用。</li></ol><p><strong>测量密码系统安全性的基本标准</strong></p><ol><li><strong>计算安全</strong>：解密加密算法的计算能力与计算时间在实际条件下不可用。</li><li><strong>安全证明</strong>：密码系统的解密依赖于对数学问题深入研究的解决方案。理论上保证安全。</li><li><strong>无条件的安全</strong>：攻击者不能在用没有限制计算能力与时间的基础上破译加密算法。极限状态下的安全。</li></ol><p>除了一次性加密算法，理论上还没有绝对安全的密码系统。在实际应用中，只要能够证明所采用的密码系统是计算安全的，就有理由相信加密算法是安全的。[1]</p><h1 id="安全地存储密码" tabindex="-1"><a class="header-anchor" href="#安全地存储密码" aria-hidden="true">#</a> 安全地存储密码</h1><h3 id="委托给可信任的第三方存储——openid技术" tabindex="-1"><a class="header-anchor" href="#委托给可信任的第三方存储——openid技术" aria-hidden="true">#</a> 委托给可信任的第三方存储——<strong>OpenID</strong>技术</h3><p>OpenID的理念是用第三方来完成用户验证。</p><p>目前国外的网站如谷歌、雅虎等，国内的如腾讯等都已经提供OpenID服务。</p><p>如果我们开发一个网站并选择谷歌的OpenID服务，那么用户就可以用Gmail的账号和密码登录，接下来用户认证的事情将由谷歌完成。</p><p>优点：</p><ul><li>没必要自己存储用户名和密码，也就没必要考虑存储密码的安全性问题，从而减少开发的成本。</li><li>用户不用在网站上注册新的用户名和密码。这样既免去了填写资料的麻烦，也减去了记住一对新的用户名和密码的负担。</li></ul><h3 id="用hash算法加密密码" tabindex="-1"><a class="header-anchor" href="#用hash算法加密密码" aria-hidden="true">#</a> 用Hash算法加密密码</h3><p>常用的几种单向的哈希算法：</p><ul><li>MD5（已被破解，不建议在产品中使用）</li><li>SHA系列（SHA1、SHA256、SHA384、SHA512等）</li></ul><p>只使用哈希算法还是不够安全：</p><ul><li>猜测密码，找有没有相同的哈希值（类似离线攻击）</li><li>彩虹表（事先计算好大量密码与对应的各种哈希算法的哈希值）</li></ul><h3 id="加盐提高安全性" tabindex="-1"><a class="header-anchor" href="#加盐提高安全性" aria-hidden="true">#</a> 加盐提高安全性</h3><p>为了应对彩虹表，我们可以先往明文密码加盐，然后再对加盐之后的密码用哈希算法加密。</p><p>所谓的盐是一个随机的字符串，往明文密码里加盐就是把明文密码和一个随机的字符串拼接在一起。由于盐在密码校验的时候还要用到，因此通常盐和密码的哈希值是存储在一起的。</p><p>需要注意的是：我们要确保往每个密码里添加随机的唯一的盐，而不是让所有密码共享一样的盐。（否则可以针对这个盐生成彩虹表）</p><p>破解方法：</p><ul><li>穷举法。由于哈希算法的快速高效，任何6位的纯数字密码即使加盐之后也能在数秒之内破解。随着计算能力的提高，黑客们低成本并且高效地破解高级别密码愈发存在可能。</li><li>通过历次密码泄露事件收集大量常用密码。这些常用的密码即使加盐也很容易破解。</li></ul><h3 id="用bcrypt或者pbkdf2增加破解的难度" tabindex="-1"><a class="header-anchor" href="#用bcrypt或者pbkdf2增加破解的难度" aria-hidden="true">#</a> 用BCrypt或者PBKDF2增加破解的难度</h3><p>为了应对暴力破解法，我们需要非常耗时的哈希算法。BCrypt算法应运而生。</p><p>BCrypt最大的特点是我们可以通过参数设置重复计算的次数。显然，重复计算的次数越多耗时越长。</p>',27),d={href:"http://bcrypt.sourceforge.net/%EF%BC%89%E5%AE%9E%E7%8E%B0%E4%BA%86BCrypt%E7%AE%97%E6%B3%95%E5%B9%B6%E8%A2%AB%E4%B8%9A%E7%95%8C%E5%B9%BF%E6%B3%9B%E9%87%87%E7%94%A8%E3%80%82",target:"_blank",rel:"noopener noreferrer"},c=l('<p>PBKDF2同样也可以通过参数设定重复计算的次数从而延长计算时间。[3]</p><h1 id="安全地传输密码" tabindex="-1"><a class="header-anchor" href="#安全地传输密码" aria-hidden="true">#</a> 安全地传输密码</h1><h3 id="非对称加密" tabindex="-1"><a class="header-anchor" href="#非对称加密" aria-hidden="true">#</a> 非对称加密</h3><p>非对称加密的模式是：</p><ul><li>乙方生成两把密钥（公钥和私钥）。公钥是公开的，任何人都可以获得，私钥则是保密的</li><li>甲方获取乙方的公钥，然后用它对信息加密</li><li>乙方得到加密后的信息，用私钥解密。</li></ul><p>即使黑客拿到了公钥，没有私钥也是没有办法解密，不考虑彩虹表的情况，完全可以长期使用一对秘钥。[6]</p><p><strong>GPG加密</strong></p><p>GPG全称 GNU Privacy Guard，是非对称加密。</p><p>如果你想给谁发送加密信息，首先你要得到他的公钥，然后通过该公钥加密后传给他，对方利用自己的私钥就可解密并读取文件了。[4]</p><p><strong>RSA算法</strong></p>',10),u={href:"http://www.ruanyifeng.com/blog/2013/06/rsa_algorithm_part_one.html",target:"_blank",rel:"noopener noreferrer"},_=l('<h3 id="对称加密" tabindex="-1"><a class="header-anchor" href="#对称加密" aria-hidden="true">#</a> 对称加密</h3><p>对称加密的模式是：</p><ul><li>甲方选择某一种加密规则，对信息进行加密</li><li>乙方使用同一种规则，对信息进行解密[6]</li></ul><p>对称加密两种常用算法：</p><ul><li>分组密码：每次只对固定长度的比特块进行加密，比如DES;</li><li>流密码：将提供的大量比特作为输入并可连续运行，从而加密；[5]</li></ul><p>客户端和服务端进行通信，采用对称加密，如果只使用一个秘钥，很容易破解；如果每次用不同的秘钥，海量秘钥的管理和传输成本又会比较高。[6]</p><h3 id="https" tabindex="-1"><a class="header-anchor" href="#https" aria-hidden="true">#</a> HTTPS</h3><p>基于HTTP协议，通过SSL或TLS提供加密处理数据、验证对方身份以及数据完整性保护。</p><p>特点：</p><ul><li>内容加密：采用混合加密技术，中间者无法直接查看明文内容。</li><li>验证身份：通过证书认证客户端访问的是自己的服务器。</li><li>保护数据完整性：防止传输的内容被中间人冒充或篡改。[7]</li></ul><h1 id="其它可能的攻击方式及相应的防范措施" tabindex="-1"><a class="header-anchor" href="#其它可能的攻击方式及相应的防范措施" aria-hidden="true">#</a> 其它可能的攻击方式及相应的防范措施</h1><p>这里只考虑从网站服务器上破解用户密码的方法。</p><h3 id="在线攻击" tabindex="-1"><a class="header-anchor" href="#在线攻击" aria-hidden="true">#</a> 在线攻击</h3><p>通过代码在网站的用户验证环节试探用户的用户名和密码。</p><p>攻击之前需要获取网站的网站协议(<code>http</code>,<code>https</code>,<code>ftp</code>,<code>pop3</code>,…)、完整的登录url（一般不可见）、登录失败信息(<code>Login failed</code>,<code>请检查用户名、密码</code>,…)。</p><p>攻击流程：比如要攻击用户&#39;Admin&#39;的密码：使用程序循环模拟用户登录行为，从字典中依次选取密码，组装后向网站发送登录请求(<code>request</code>)，接收网站的反馈信息（<code>response</code>）并加以分析，如果没有返回登录失败信息，说明攻击成功。</p><p>现有的软件工具：</p><ul><li>获取网站基本信息：<code>BurpSuite</code></li><li>表单密码破解：<code>hydra</code></li></ul><p>防范措施：</p><ul><li>验证码、滑块拼图、限制失败登陆次数等。无法彻底杜绝。[2]</li></ul><h3 id="离线攻击" tabindex="-1"><a class="header-anchor" href="#离线攻击" aria-hidden="true">#</a> 离线攻击</h3><p>将获取的哈希密码保存到本地，利用自己的计算机对密码进行离线破解。</p><p>必须要先判断密码的加密方式。之后将字典中的密码进行依次加密、比对。[2]</p><p>现有的软件工具：</p><ul><li><code>John the Ripper</code></li><li><code>hashcat</code></li></ul><p>防范措施：</p><ul><li>优化哈希密码的存储技术，采取特殊的加密方式等。</li></ul><h1 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h1>',28),f={href:"https://www.fisec.cn/1244.html",target:"_blank",rel:"noopener noreferrer"},g={href:"https://cloud.tencent.com/developer/news/313489",target:"_blank",rel:"noopener noreferrer"},b={href:"https://www.cnblogs.com/jpfss/p/11024665.html",target:"_blank",rel:"noopener noreferrer"},m={href:"http://blog.sina.com.cn/s/blog_71f3890901011ig0.html",target:"_blank",rel:"noopener noreferrer"},B={href:"https://blog.csdn.net/chuanglan/article/details/80627366",target:"_blank",rel:"noopener noreferrer"},E={href:"https://zhuanlan.zhihu.com/p/36603247",target:"_blank",rel:"noopener noreferrer"},w={href:"https://blog.csdn.net/xiaoming100001/article/details/81109617",target:"_blank",rel:"noopener noreferrer"};function x(k,y){const a=h("ExternalLinkIcon");return o(),i("div",null,[s,r("p",null,[e("目前已有开源项目（"),r("a",d,[e("http://bcrypt.sourceforge.net/）实现了BCrypt算法并被业界广泛采用。"),t(a)])]),c,r("p",null,[e("RSA算法原理："),r("a",u,[e("http://www.ruanyifeng.com/blog/2013/06/rsa_algorithm_part_one.html"),t(a)])]),_,r("p",null,[e("[1] 渔翁信息. 密码系统安全性的定义 [EB/OL]. "),r("a",f,[e("https://www.fisec.cn/1244.html"),t(a)]),e(", 2019-02-12")]),r("p",null,[e("[2] 平平说科技. 黑客技术入门：密码攻击的原理和方法 [EB/OL]. "),r("a",g,[e("https://cloud.tencent.com/developer/news/313489"),t(a)]),e(", 2018-09-13")]),r("p",null,[e("[3] 星朝. 如何安全地存储密码 [EB/OL]. "),r("a",b,[e("https://www.cnblogs.com/jpfss/p/11024665.html"),t(a)]),e(", 2019-06-14")]),r("p",null,[e("[4] 守株待兔. GPG 加密解密简明教程 [EB/OL]. "),r("a",m,[e("http://blog.sina.com.cn/s/blog_71f3890901011ig0.html"),t(a)]),e(", 2012-04-19")]),r("p",null,[e("[5] kph_Hajash. 网络信息传输的安全机制 [EB/OL]. "),r("a",B,[e("https://blog.csdn.net/chuanglan/article/details/80627366"),t(a)]),e(", 2018-06-08")]),r("p",null,[e("[6] 徐辛承. 如何加密传输和存储用户密码 [EB/OL]. "),r("a",E,[e("https://zhuanlan.zhihu.com/p/36603247"),t(a)]),e(", 2018-05-09")]),r("p",null,[e("[7] 会飞的狗~. HTTP和HTTPS协议，看一篇就够了 [EB/OL]. "),r("a",w,[e("https://blog.csdn.net/xiaoming100001/article/details/81109617"),t(a)]),e(", 2019-08-03")])])}const S=n(p,[["render",x],["__file","how_do_websites_save_passwords_safely.html.vue"]]);export{S as default};
